  const textElements = document.querySelectorAll('text');
  const carNames = Array.from(textElements).map(t => t.textContent);

  return {
    pointCount: points.length,
    uniqueColors,
    visibleTextCount: textElements.length,
    sampleText: carNames.slice(0, 10)
  };
})()"

agent-browser eval "(() => {
  const paths = Array.from(document.querySelectorAll('path'));
  const points = paths.filter(p => p.getAttribute('d') && p.getAttribute('d').includes('m') || p.getAttribute('d').includes('M'));

  // Filter for paths that are likely symbols (small area)
  const symbols = points.filter(p => {
    const box = p.getBBox();
    return box.width < 20 && box.height < 20;
  });

  const colors = symbols.map(p => p.getAttribute('fill') || window.getComputedStyle(p).fill);
  const uniqueColors = [...new Set(colors)];

  return {
    symbolCount: symbols.length,
    uniqueColors,
    firstSymbolColor: colors[0]
  };
})()"

